previewCss:
.darma-loader-darma-custom-173 {
  color: var(--loader-color, #ea580c);
width: 60px;
aspect-ratio: 2;
--_g: no-repeat radial-gradient(circle closest-side,currentColor 90%,#0000);
background:
var(--_g) 0% 50%,
var(--_g) 50% 50%,
var(--_g) 100% 50%;
background-size: calc(100%/3) 50%;
animation: darma-loader-darma-custom-173-l3 1s infinite linear;
}
@keyframes darma-loader-darma-custom-173-l3 {
20%{background-position:0% 0%, 50% 50%,100% 50%}
40%{background-position:0% 100%, 50% 0%,100% 50%}
60%{background-position:0% 50%, 50% 100%,100% 0%}
80%{background-position:0% 50%, 50% 50%,100% 100%}
}

